8	 * @param {string[]} lineCommentTypes - list of character strings that denote line comments
9	 */
10	export const lineComment = (lineCommentTypes: string[]) =>
11	  new RegExp(`(?:${lineCommentTypes.map(escapeRegExp).join('|')}).*?(?=\r\n|\r|\n|$)`, 'uy');
