13	/**
14	 * Builds a RegExp for matching either open- or close-parenthesis patterns
15	 */
16	export const parenthesis = (kind: 'open' | 'close', extraParens: ('[]' | '{}')[] = []): RegExp => {
17	  const index = kind === 'open' ? 0 : 1;
18	  const parens = ['()', ...extraParens].map(pair => pair[index]);
19	  return patternToRegex(parens.map(escapeRegExp).join('|'));
20	};
