const PIPE_IDENTIFIER_CLAUSES = ['AGGREGATE', 'EXTEND'];

// After a |> pipe operator, some verbs (LIMIT, JOIN, AS, AGGREGATE, EXTEND)
// tokenize as something other than RESERVED_CLAUSE outside of pipe syntax
// (or not as a reserved word at all). Reclassify them to RESERVED_CLAUSE here
// so the grammar can parse every pipe-verb the same way.
//
// Also reclassifies a GROUP BY that's nested directly inside an AGGREGATE verb
// to its own token type, so the grammar can unambiguously attach it to the
// enclosing AGGREGATE clause instead of also considering it a sibling clause.
function reclassifyPipeClauseKeywords(tokens: Token[]): Token[] {
  let prevSignificant: Token = EOF_TOKEN;
  let currentPipeVerb: string | undefined;

  return tokens.map(token => {
    const isComment =
      token.type === TokenType.LINE_COMMENT ||
      token.type === TokenType.BLOCK_COMMENT ||
      token.type === TokenType.DISABLE_COMMENT;

    let result = token;

    if (token.type === TokenType.PIPE) {
      currentPipeVerb = undefined;
    } else if (prevSignificant.type === TokenType.PIPE) {
      if (token.type === TokenType.LIMIT || token.type === TokenType.RESERVED_JOIN) {
        result = { ...token, type: TokenType.RESERVED_CLAUSE };
      } else if (token.type === TokenType.RESERVED_KEYWORD && token.text === 'AS') {
        result = { ...token, type: TokenType.RESERVED_CLAUSE };
      } else if (
        token.type === TokenType.IDENTIFIER &&
        PIPE_IDENTIFIER_CLAUSES.includes(token.text.toUpperCase())
      ) {
        result = {
          ...token,
          type: TokenType.RESERVED_CLAUSE,
          text: equalizeWhitespace(token.text.toUpperCase()),
        };
      }
      currentPipeVerb = result.text;
    } else if (
      currentPipeVerb === 'AGGREGATE' &&
      token.type === TokenType.RESERVED_CLAUSE &&
      token.text === 'GROUP BY'
    ) {
      result = { ...token, type: TokenType.PIPE_AGGREGATE_GROUP_BY };
    }

    if (!isComment) {
      prevSignificant = result;
    }
    return result;
  });
